class Solution:
    def minInversionCount(self, nums, k):
        n = len(nums)
        best = None
        for s in range(0, n - k + 1):
            window = nums[s:s + k]
            inv = 0
            for i in range(len(window)):
                for j in range(i + 1, len(window)):
                    if window[i] > window[j]:
                        inv += 1
            if best is None or inv < best:
                best = inv
        return best

