class Solution:
    def minInversionCount(self, nums: List[int], k: int) -> int:
        n = len(nums)
        sorted_vals = sorted(set(nums))
        comp = {v: i + 1 for i, v in enumerate(sorted_vals)}
        m = len(sorted_vals)
        bit = [0] * (m + 1)

        def update(idx, delta):
            while idx <= m:
                bit[idx] += delta
                idx += idx & (-idx)

        def prefix(idx):
            s = 0
            while idx > 0:
                s += bit[idx]
                idx -= idx & (-idx)
            return s

        def count_less(v):
            c = comp[v]
            return prefix(c - 1)

        def count_greater(v):
            c = comp[v]
            return prefix(m) - prefix(c)

        total = 0
        for i in range(k):
            v = nums[i]
            total += count_greater(v)
            update(comp[v], 1)
        best = total
        for s in range(1, n - k + 1):
            left = nums[s - 1]
            total -= count_less(left)
            update(comp[left], -1)
            newv = nums[s + k - 1]
            total += count_greater(newv)
            update(comp[newv], 1)
            if total < best:
                best = total
        return best

