var minInversionCount = function(nums, k) {
    const n = nums.length;
    const sortedVals = Array.from(new Set(nums)).sort((a, b) => a - b);
    const comp = new Map();
    sortedVals.forEach((v, i) => comp.set(v, i + 1));
    const m = sortedVals.length;
    const bit = new Array(m + 1).fill(0);

    function update(idx, delta) {
        while (idx <= m) { bit[idx] += delta; idx += idx & (-idx); }
    }
    function prefix(idx) {
        let s = 0;
        while (idx > 0) { s += bit[idx]; idx -= idx & (-idx); }
        return s;
    }
    function countLess(v) {
        const c = comp.get(v);
        return prefix(c - 1);
    }
    function countGreater(v) {
        const c = comp.get(v);
        return prefix(m) - prefix(c);
    }

    let total = 0;
    for (let i = 0; i < k; i++) {
        const v = nums[i];
        total += countGreater(v);
        update(comp.get(v), 1);
    }
    let best = total;
    for (let s = 1; s <= n - k; s++) {
        const left = nums[s - 1];
        total -= countLess(left);
        update(comp.get(left), -1);
        const newv = nums[s + k - 1];
        total += countGreater(newv);
        update(comp.get(newv), 1);
        if (total < best) best = total;
    }
    return best;
};
